"(function() {
    if (window.__stonlyFileUploadInterceptInstalled) return;
    window.__stonlyFileUploadInterceptInstalled = true;

    var pendingFileInput = null;

    document.addEventListener('click', function(e) {
        var target = e.target;
        while (target && target !== document) {
            if (target.tagName === 'INPUT' && target.type === 'file') {
                e.preventDefault();
                e.stopPropagation();
                e.stopImmediatePropagation();
                pendingFileInput = target;
                window.webkit.messageHandlers."

".postMessage({
                    type: 'stonlyFileUploadRequest',
                    accept: target.accept || '',
                    multiple: target.multiple || false
                });
                return false;
            }
            target = target.parentElement;
        }
    }, true);

    window.__stonlySetFileOnInput = function(fileName, mimeType, base64Data) {
        if (!pendingFileInput) return;
        try {
            var byteChars = atob(base64Data);
            var byteNums = new Array(byteChars.length);
            for (var i = 0; i < byteChars.length; i++) {
                byteNums[i] = byteChars.charCodeAt(i);
            }
            var byteArray = new Uint8Array(byteNums);
            var blob = new Blob([byteArray], { type: mimeType });
            var file = new File([blob], fileName, { type: mimeType });
            var dt = new DataTransfer();
            dt.items.add(file);
            pendingFileInput.files = dt.files;
            var evt = new Event('change', { bubbles: true });
            pendingFileInput.dispatchEvent(evt);
        } catch(err) {}
        pendingFileInput = null;
    };

    window.__stonlyCancelFileUpload = function() {
        pendingFileInput = null;
    };
})();"

