" (function() {
     function updateCloseButtonBackground() {
         // Find all buttons with class containing "CloseButton__CloseFunction"
         var buttons = document.querySelectorAll('button[class*="CloseButton__CloseFunction"]');

         buttons.forEach(function(button) {
             // Find div elements inside the button 

             button.style.cssText += '; z-index: 1000 !important;';
             var divs = button.querySelectorAll('div');
             divs.forEach(function(div) {
                 // Change background-color to black
                 div.style.backgroundColor = 'rgb(0,0,0)';

             });
         });
     }

     // Run initially
     updateCloseButtonBackground();

     // Observer for close button changes
     var closeButtonObserver = new MutationObserver(function(mutations) {
         mutations.forEach(function(mutation) {
             if (mutation.addedNodes.length > 0) {
                 updateCloseButtonBackground();
             }
         });
     });

     closeButtonObserver.observe(document.body, {
         childList: true,
         subtree: true
     });
 })();"

"(function() {


    function modifyYouTubeIframes() {
        var iframes = document.querySelectorAll('iframe'); 
        var youtubeCount = 0;

        iframes.forEach(function(iframe, index) {
            if (iframe.src.includes('youtube.com/embed') || iframe.src.includes('youtube-nocookie.com/embed')) {
                youtubeCount++;

                // Enable fullscreen instead of disabling it
                iframe.setAttribute('allowfullscreen', 'true');
                iframe.setAttribute('webkitallowfullscreen', 'true');
                iframe.setAttribute('mozallowfullscreen', 'true');


                // Listen for fullscreen events on YouTube iframe
                try {
                    iframe.addEventListener('fullscreenchange', function() {
                        if (document.fullscreenElement === iframe) {
                            window.webkit.messageHandlers.iosListener.postMessage({
                                type: 'youtubeFullscreenEnter',
                                iframe: iframe.src,
                                timestamp: Date.now()
                            });
                        } else {
                            window.webkit.messageHandlers.iosListener.postMessage({
                                type: 'youtubeFullscreenExit',
                                iframe: iframe.src,
                                timestamp: Date.now()
                            });
                        }
                    });

                    iframe.addEventListener('webkitfullscreenchange', function() {
                        if (document.webkitFullscreenElement === iframe) {
                            window.webkit.messageHandlers.iosListener.postMessage({
                                type: 'youtubeFullscreenEnter',
                                iframe: iframe.src,
                                timestamp: Date.now()
                            });
                        } else {
                            window.webkit.messageHandlers.iosListener.postMessage({
                                type: 'youtubeFullscreenExit', 
                                iframe: iframe.src,
                                timestamp: Date.now()
                            });
                        }
                    });

                } catch(e) {
                }
            }
        });

    }

    // Run initially
    modifyYouTubeIframes();

    // Enhanced observer for YouTube changes
    var youtubeObserver = new MutationObserver(function(mutations) {
        var shouldCheck = false;
        mutations.forEach(function(mutation) {
            mutation.addedNodes.forEach(function(node) {
                if (node.tagName === 'IFRAME') {
                    shouldCheck = true;
                }
            });
        });

        if (shouldCheck) {
            setTimeout(modifyYouTubeIframes, 100);
        }
    });

    youtubeObserver.observe(document.body, {
        childList: true,
        subtree: true,
        attributes: true
    });

    // Additional periodic check specifically for YouTube embeds
    setInterval(function() {
        modifyYouTubeIframes();
    }, 3000);

})();"

"(function() {



    function modifyVimeoIframes() {
        var iframes = document.querySelectorAll('iframe');

        var vimeoCount = 0;
        iframes.forEach(function(iframe) {
            if (iframe.src.includes('vimeo.com/video') || iframe.src.includes('player.vimeo.com')) {
                vimeoCount++;

                var src = iframe.src;
                iframe.setAttribute('allowfullscreen', 'true');
                iframe.setAttribute('webkitallowfullscreen', 'true');

                // Listen for Vimeo fullscreen events
                try {
                    iframe.contentWindow.postMessage(JSON.stringify({
                        method: 'addEventListener',
                        value: 'enterfullscreen'
                    }), '*');

                    iframe.contentWindow.postMessage(JSON.stringify({
                        method: 'addEventListener', 
                        value: 'exitfullscreen'
                    }), '*');
                } catch(e) {
              }
            }
        }); 
    }

    // Listen for Vimeo player messages only
    window.addEventListener('message', function(event) {
        if (event.origin !== 'https://player.vimeo.com') return;

        try {
            var data = JSON.parse(event.data);
            if (data.event === 'enterfullscreen') {
                window.webkit.messageHandlers.iosListener.postMessage({
                    type: 'vimeoFullscreenEnter',
                    timestamp: Date.now()
                });
            } else if (data.event === 'exitfullscreen') {
               window.webkit.messageHandlers.iosListener.postMessage({
                    type: 'vimeoFullscreenExit',
                    timestamp: Date.now()
                });
            }
        } catch(e) {
        }
    });



    // Run initially
    modifyVimeoIframes();

    // Observer for Vimeo iframe changes
    var vimeoObserver = new MutationObserver(function(mutations) {
        var hasNewIframes = false;
        mutations.forEach(function(mutation) {
            mutation.addedNodes.forEach(function(node) {
                if (node.tagName === 'IFRAME') {
                    hasNewIframes = true;
                }
            });
        });

        if (hasNewIframes) {
            modifyVimeoIframes();
        }
    });

    vimeoObserver.observe(document.body, {
        childList: true,
        subtree: true,
        attributes: true,
        characterData: true
    });
})();"

